module RefModule(  
    input wire D,  
    input wire E,  
    input wire CLK,  
    output reg Q  
);  
    reg unused_master;  
    always @(posedge CLK) begin  
        if (E)  
            unused_master <= D;  
    end  
    always @(negedge CLK) begin  
        Q <= unused_master;  
    end  
endmodule
